  return [{ json: { route: 'unknown', sessionId: '', chatId: incomingChatId, callbackQueryId: '', messageId: 0, fileId: '' } }];
}
if (cb) {
  const parts = (cb.data || '').split(':');
  const route = (parts[0] || '') + ':' + (parts[1] || '');
  const sessionId = parts[2] || '';
  return [{ json: { route, sessionId, chatId: String(cb.message?.chat?.id ?? ''), callbackQueryId: cb.id, messageId: cb.message?.message_id ?? 0, fileId: '' } }];
}
if (msg && Array.isArray(msg.photo) && msg.photo.length) {
  const largest = msg.photo[msg.photo.length - 1];
  return [{ json: { route: 'msg:photo', sessionId: '', chatId: String(msg.chat?.id ?? ''), callbackQueryId: '', messageId: 0, fileId: largest.file_id } }];
}
if (msg && msg.text && msg.text.toLowerCase().trim() === 'post') {
  return [{ json: { route: 'msg:post', sessionId: '', chatId: String(msg.chat?.id ?? ''), callbackQueryId: '', messageId: 0, fileId: '' } }];
}
return [{ json: { route: 'unknown', sessionId: '', chatId: String(msg?.chat?.id ?? ''), callbackQueryId: '', messageId: 0, fileId: '' } }];

const pr = $('Parse Reply').item.json;
const ackMap = {'q1:y':'✅ Posting today!','q1:n':'❌ Skipping today.','q2:pic':'🖼 Picture post selected.','q2:vid':'🎬 Video post selected.','q2b:own':'📷 Upload your own photo.','q2b:gen':'✨ Generating an image.','q3:ok':'✅ Approved!','q3:rg':'🔁 Regenerating...','q3:cx':'❌ Cancelled.','q3:rv':'🔁 Regenerating video...'};
return [{ json: { ...pr, ackText: ackMap[pr.route] || '✓' } }];

let arr;
const first = $input.first().json;
if (Array.isArray(first)) {
  arr = first.filter(i => typeof i.src === "string" && i.src.startsWith("http"));
