const themeScenes = {
  'Food spotlight': 'Create a stunning editorial food photograph for The Miners Arms: beautifully presented Indian or pub food on a warm wooden table with candlelight and soft bokeh background. Apply a warm, rich colour grade. Elegant gold text about the food offering is naturally part of the composition.',
